def longest_non_decreasing_subsequence(arr1, arr2):
    m, n = len(arr1), len(arr2)

    # Create two tables to store lengths of longest increasing subsequence ending with arr1[i] and arr2[j]
    dp1 = [0]*m
    dp2 = [0]*n

    # Length of longest increasing subsequence ending with arr1[i]
    prev_i = [-1]*m
    # Length of longest increasing subsequence ending with arr2[j]
    prev_j = [-1]*n

    for i in range(m):
        for j in range(n):
            if arr1[i] <= arr2[j] and dp1[i] < dp2[j] + 1:
                dp1[i] = dp2[j] + 1
                prev_i[i] = j

            if dp1[i] <= dp1[i-1]:
                dp1[i] = dp1[i-1]

    max_length = 0
    start_index = -1

    for i in range(m):
        if dp1[i] > max_length:
            max_length = dp1[i]
            start_index = i

    # Similarly, fill the dp2 table for arr2
    for j in range(n):
        for i in range(m):
            if arr2[j] <= arr1[i] and dp2[j] < dp1[i] + 1:
                dp2[j] = dp1[i] + 1
                prev_j[j] = i

            if dp2[j] <= dp2[j-1]:
                dp2[j] = dp2[j-1]

    for j in range(n):
        if dp2[j] > max_length:
            max_length = dp2[j]
            start_index = j

    # Construct the longest non-decreasing subarray
    if start_index == -1:
        return max_length
    else:
        result = []
        index = start_index
        while index != -1:
            result.append(arr1[index]) if index < len(arr1) else result.append(arr2[index])
            index = prev_i[index] if index >= 0 else prev_j[index]
        return result[::-1]

