    merged_list = nums1 + nums2
    max_length = 0
    for i in range(len(merged_list)):
        j = i - 1
        while j >= 0 and merged_list[j] > merged_list[i]:
            j -= 1
        if j + 1 > max_length:
            max_length = j + 1
    return max_length

